using System;
using UnityEngine;

/// <summary>
/// Tarefa #31 — camada fina sobre <see cref="LoadingScreenController"/>
/// especializada em trocas de cena por área: traduz um <see cref="AreaData"/>
/// (via "sceneName") numa chamada a LoadingScreenController.LoadScene, e
/// expõe <see cref="IsLoading"/> para AreaManager/AreaTransition evitarem
/// pedidos repetidos enquanto a troca está a decorrer.
///
/// Singleton com auto-fallback (mesmo padrão de outros managers — Tarefa #15,
/// ver PlayerProgress.cs para a explicação completa).
/// </summary>
public class SceneLoader : MonoBehaviour
{
    public static SceneLoader Instance { get; private set; }

    private bool isAutoFallback;

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            if (Instance.isAutoFallback && !isAutoFallback)
            {
                Destroy(Instance.gameObject);
            }
            else
            {
                Destroy(gameObject);
                return;
            }
        }

        Instance = this;
        transform.SetParent(null);
        DontDestroyOnLoad(gameObject);
    }

    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.BeforeSceneLoad)]
    private static void EnsureExists()
    {
        if (Instance != null) return;
        var go = new GameObject(nameof(SceneLoader) + " (Fallback)");
        var instance = go.AddComponent<SceneLoader>();
        instance.isAutoFallback = true;
    }

    /// <summary>true enquanto uma troca de cena estiver em curso (delega em LoadingScreenController.IsLoading).</summary>
    public bool IsLoading => LoadingScreenController.Instance != null && LoadingScreenController.Instance.IsLoading;

    /// <summary>
    /// Carrega a cena de "area" (AreaData.sceneName) com fade
    /// (LoadingScreenController.LoadScene). "onLoaded" é chamado depois da
    /// cena activar mas ANTES do fade out — AreaManager usa isto para
    /// reposicionar o player no AreaSpawnPoint pedido e actualizar
    /// WorldState.CurrentArea antes do jogador voltar a ver o ecrã.
    /// Sem efeito se "area"/"area.sceneName" forem inválidos, se já houver
    /// uma troca em curso, ou se LoadingScreenController não existir.
    /// </summary>
    public void LoadArea(AreaData area, Action onLoaded = null)
    {
        if (area == null || string.IsNullOrEmpty(area.sceneName))
        {
            Debug.LogWarning("[SceneLoader] AreaData sem 'sceneName' — não é possível carregar.");
            return;
        }

        if (IsLoading) return;

        if (LoadingScreenController.Instance != null)
            LoadingScreenController.Instance.LoadScene(area.sceneName, onLoaded);
        else
            Debug.LogWarning("[SceneLoader] LoadingScreenController.Instance não encontrado.");
    }
}
